using System.Collections.Concurrent;namespace ScraperBackendService.Core.Concurrency;/// <summary>/// Controls the maximum number of concurrent requests to a specific provider./// Each slot enters a configurable cooldown period after release, during which/// it cannot be re-acquired. This naturally throttles request frequency./// </summary>/// <remarks>/// With <c>MaxConcurrentRequests=2</c> and <c>SlotCooldown=5s</c>:/// <code>/// Slot 0: ─[fetch]─|5s cooldown|─[fetch]─|5s cooldown|─/// Slot 1: ─[fetch]─|5s cooldown|─[fetch]─|5s cooldown|─/// </code>/// Burst of 2, then at least 5s before either slot can be reused./// </remarks>public sealed class ProviderConcurrencyLimiter : IDisposable{    private readonly SemaphoreSlim _sem;    private readonly int _max;    private readonly TimeSpan _cooldown;    private readonly ConcurrentQueue<int> _availableSlots;    private int _disposed;    /// <summary>    /// Gets the provider name for this limiter instance.    /// </summary>    public string ProviderName { get; }    /// <summary>    /// Initializes a new instance of the ProviderConcurrencyLimiter class.    /// </summary>    /// <param name="maxConcurrent">Maximum number of concurrent operations allowed</param>    /// <param name="cooldown">    /// Cooldown period after a slot is released before it can be re-acquired.    /// Set to <see cref="TimeSpan.Zero"/> to disable cooldown.    /// </param>    /// <param name="providerName">Optional provider name for identification</param>    public ProviderConcurrencyLimiter(int maxConcurrent, TimeSpan cooldown, string? providerName = null)    {        _max = maxConcurrent <= 0 ? 1 : maxConcurrent;        _cooldown = cooldown < TimeSpan.Zero ? TimeSpan.Zero : cooldown;        _sem = new SemaphoreSlim(_max, _max);        _availableSlots = new ConcurrentQueue<int>();        ProviderName = providerName ?? "Unknown";        for (int i = 0; i < _max; i++)        {            _availableSlots.Enqueue(i);        }    }    /// <summary>    /// Tries to acquire a slot with timeout.    /// </summary>    /// <param name="millisecondsTimeout">Timeout in milliseconds</param>    /// <param name="ct">Cancellation token</param>    /// <returns>A concurrency slot if acquired within timeout, null otherwise</returns>    public async Task<ConcurrencySlot?> TryWaitAndAcquireSlotAsync(int millisecondsTimeout, CancellationToken ct)    {        var acquired = await _sem.WaitAsync(millisecondsTimeout, ct).ConfigureAwait(false);        if (!acquired)            return null;        if (_availableSlots.TryDequeue(out var slotId))            return new ConcurrencySlot(this, slotId);        // Fallback: should not happen under normal operation, but keeps the        // system running if the queue and semaphore drift apart.        return new ConcurrencySlot(this, slotId: -1);    }    /// <summary>    /// Releases a specific slot. If a cooldown is configured and    /// <paramref name="immediate"/> is <c>false</c>, the slot stays    /// unavailable for the cooldown duration; otherwise it is returned immediately.    /// </summary>    /// <param name="slotId">Slot identifier to release.</param>    /// <param name="immediate">    /// <c>true</c> to skip the cooldown (e.g. cache-hit path);    /// <c>false</c> (default) to apply the normal cooldown.    /// </param>    internal void ReleaseSlot(int slotId, bool immediate = false)    {        if (immediate || _cooldown <= TimeSpan.Zero || Volatile.Read(ref _disposed) != 0)        {            _availableSlots.Enqueue(slotId);            _sem.Release();            return;        }        // Schedule a delayed release – the slot is genuinely unavailable        // during the cooldown because neither the queue nor the semaphore        // are updated until the delay completes.        _ = DelayedReleaseAsync(slotId);    }    private async Task DelayedReleaseAsync(int slotId)    {        try        {            await Task.Delay(_cooldown).ConfigureAwait(false);        }        catch (ObjectDisposedException)        {            return;        }        if (Volatile.Read(ref _disposed) != 0)            return;        _availableSlots.Enqueue(slotId);        try        {            _sem.Release();        }        catch (ObjectDisposedException)        {            // Limiter disposed during cooldown – safe to ignore.        }    }    /// <inheritdoc />    public void Dispose()    {        Volatile.Write(ref _disposed, 1);        _sem.Dispose();    }    /// <summary>Current available slots (for diagnostics).</summary>    public int CurrentCount => _sem.CurrentCount;    /// <summary>Configured maximum concurrent slots.</summary>    public int MaxCount => _max;    /// <summary>Configured cooldown period.</summary>    public TimeSpan Cooldown => _cooldown;}/// <summary>/// Represents an acquired concurrency slot that should be disposed when done./// Set <see cref="SkipCooldown"/> to <c>true</c> before disposing to release/// the slot immediately (e.g. when the request was served from cache)./// </summary>public sealed class ConcurrencySlot : IDisposable{    private readonly ProviderConcurrencyLimiter _limiter;    private bool _disposed;    /// <summary>    /// Gets the unique identifier for this concurrency slot.    /// </summary>    public int SlotId { get; }    /// <summary>    /// When <c>true</c>, the slot will be returned to the pool immediately    /// on <see cref="Dispose"/> without entering the cooldown period.    /// Useful for cache-hit paths where no actual network request was made.    /// </summary>    public bool SkipCooldown { get; set; }    internal ConcurrencySlot(ProviderConcurrencyLimiter limiter, int slotId)    {        _limiter = limiter;        SlotId = slotId;    }    /// <summary>    /// Releases the concurrency slot back to the limiter.    /// </summary>    public void Dispose()    {        if (!_disposed)        {            _limiter.ReleaseSlot(SlotId, immediate: SkipCooldown);            _disposed = true;        }    }}